-- Snowflake init for Kafka Connect (dev/staging/prod).
-- Run with SECURITYADMIN for roles/users, SYSADMIN for DB/warehouse.

-- =====================
-- DEV
-- =====================
USE ROLE SECURITYADMIN;

CREATE ROLE IF NOT EXISTS ROLE_KAFKA_DEV;
CREATE USER IF NOT EXISTS KAFKA_CONNECT_DEV
  LOGIN_NAME = 'KAFKA_CONNECT_DEV'
  DISPLAY_NAME = 'Kafka Connect DEV'
  DEFAULT_ROLE = ROLE_KAFKA_DEV
  DEFAULT_WAREHOUSE = WH_DEV
  DEFAULT_NAMESPACE = BOOKIBET_DEV.RAW
  MUST_CHANGE_PASSWORD = FALSE;

-- Replace with the actual public key for KAFKA_CONNECT_DEV.
ALTER USER KAFKA_CONNECT_DEV
  SET RSA_PUBLIC_KEY_2='';

GRANT ROLE ROLE_KAFKA_DEV TO USER KAFKA_CONNECT_DEV;

USE ROLE SYSADMIN;

CREATE DATABASE IF NOT EXISTS BOOKIBET_DEV;
CREATE SCHEMA IF NOT EXISTS BOOKIBET_DEV.RAW;

CREATE WAREHOUSE IF NOT EXISTS WH_DEV
  WAREHOUSE_SIZE = 'XSMALL'
  AUTO_SUSPEND = 60
  AUTO_RESUME = TRUE;

GRANT USAGE ON WAREHOUSE WH_DEV TO ROLE ROLE_KAFKA_DEV;
GRANT USAGE ON DATABASE BOOKIBET_DEV TO ROLE ROLE_KAFKA_DEV;
GRANT USAGE, CREATE TABLE, INSERT, SELECT ON SCHEMA BOOKIBET_DEV.RAW TO ROLE ROLE_KAFKA_DEV;

